import{_ as t,o as e,c as r,ai as l}from"./chunks/framework.DjxHwWNk.js";const g=JSON.parse('{"title":"Общежитие № 11 УрФУ","description":"Студенческое общежитие, связанное с ранней историей «Агаты Кристи» и андеграундной средой УПИ.","frontmatter":{"title":"Общежитие № 11 УрФУ","description":"Студенческое общежитие, связанное с ранней историей «Агаты Кристи» и андеграундной средой УПИ.","outline":"deep"},"headers":[],"relativePath":"places/obschezhitie-11-urfu.md","filePath":"places/obschezhitie-11-urfu.md"}'),o={name:"places/obschezhitie-11-urfu.md"};function s(d,a,i,n,h,p){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="общежитие-no-11-урфу" tabindex="-1">Общежитие № 11 УрФУ <a class="header-anchor" href="#общежитие-no-11-урфу" aria-label="Permalink to “Общежитие № 11 УрФУ”">​</a></h1><p><strong>Общежитие № 11 УрФУ</strong> — одно из важных студенческих мест в истории уральского рока. Здесь, в середине 1980-х годов, в комнате Вадима Самойлова формировалась ранняя творческая среда будущей группы <strong>«Агата Кристи»</strong>.</p><div class="tip custom-block"><p class="custom-block-title">Кратко</p><ul><li><strong>Адрес:</strong> Екатеринбург, ул. Коминтерна, 5</li><li><strong>Период ключевого значения:</strong> середина 1980-х годов</li><li><strong>Главная роль:</strong> одно из мест становления «Агаты Кристи»</li><li><strong>Связанные группы:</strong> «Агата Кристи»</li><li><strong>Статус сегодня:</strong> действующее студенческое общежитие УрФУ</li></ul></div><h2 id="почему-это-место-важно" tabindex="-1">Почему это место важно <a class="header-anchor" href="#почему-это-место-важно" aria-label="Permalink to “Почему это место важно”">​</a></h2><p>Общежитие № 11 важно не как официальная концертная площадка, а как пространство повседневной студенческой культуры, из которой выросла часть уральского рока. В отличие от ДК и больших сцен, здесь всё происходило камерно: в комнатах, коридорах, на неформальных встречах и ночных музыкальных посиделках.</p><p>Именно в этом общежитии, в комнате Вадима Самойлова, складывалась атмосфера, которая позже повлияла на раннее звучание <strong>«Агаты Кристи»</strong>. Здесь слушали музыку, обсуждали тексты, играли на гитарах, приносили записи и вместе придумывали первые песни и аранжировки.</p><h2 id="историческая-справка" tabindex="-1">Историческая справка <a class="header-anchor" href="#историческая-справка" aria-label="Permalink to “Историческая справка”">​</a></h2><p>Общежитие № 11 Уральского федерального университета, ранее связанное с УПИ, — скромное пятиэтажное здание, которое сыграло заметную роль в становлении группы <strong>«Агата Кристи»</strong>.</p><p>В середине 1980-х годов здесь жил Вадим Самойлов — будущий лидер группы. Его комната постепенно превратилась в неформальное место встреч студентов, музыкантов и друзей с радиофака. Это было пространство, где обсуждали музыку, обменивались записями, сочиняли тексты и пробовали первые варианты песен.</p><p>В те годы студенческие общежития были центрами неформальной жизни. Здесь слушали западную музыку, спорили о поэзии, играли на гитарах и записывали первые композиции. Комната Самойлова быстро стала чем-то вроде стихийного музыкального салона и одной из первых домашних репетиционных точек будущей <strong>«Агаты Кристи»</strong>.</p><p>Именно в этом общежитии, по материалам проекта, были сделаны первые демо-записи будущих песен. Здесь формировался «самодельный» звук — сырой, искренний и связанный с духом студенческого андеграунда. Атмосфера комнаты Самойлова описывается как особенная: плакаты на стенах, магнитофоны, ночные разговоры и музыка, которая через несколько лет станет известна далеко за пределами Свердловска.</p><p>Общежитие стало не просто местом проживания, а настоящим творческим хабом. Многие студенты-музыканты начинали свой путь именно в такой среде: без официальных студий, больших сцен и профессиональной инфраструктуры, но с сильным желанием экспериментировать и создавать собственный звук.</p><p>В 2020-е годы здание продолжает использоваться как студенческое общежитие. При этом для поклонников <strong>«Агаты Кристи»</strong> оно сохраняет символическое значение как одна из точек, где начиналась ранняя история группы.</p><h2 id="геолокация" tabindex="-1">Геолокация <a class="header-anchor" href="#геолокация" aria-label="Permalink to “Геолокация”">​</a></h2><p><strong>Адрес:</strong> Екатеринбург, ул. Коминтерна, 5.</p><p>Общежитие находится в университетской части города и логично связывается с маршрутом по местам, связанным с <strong>«Агатой Кристи»</strong> и студенческим Свердловском.</p><h2 id="связанные-лица" tabindex="-1">Связанные лица <a class="header-anchor" href="#связанные-лица" aria-label="Permalink to “Связанные лица”">​</a></h2><table tabindex="0"><thead><tr><th>Имя</th><th>Роль / связь с объектом</th></tr></thead><tbody><tr><td><a href="/Knowledge-Base/people/vadim-samoilov.html">Вадим Самойлов</a></td><td>Жил здесь в студенческие годы, создавал первые песни</td></tr><tr><td><a href="/Knowledge-Base/people/gleb-samoilov.html">Глеб Самойлов</a></td><td>Часто бывал здесь в период становления группы</td></tr><tr><td><a href="/Knowledge-Base/people/alexander-kozlov.html">Александр Козлов</a></td><td>Сооснователь «Агаты Кристи», участник первых репетиций</td></tr><tr><td><a href="/Knowledge-Base/people/petr-may.html">Пётр Май</a></td><td>Первый барабанщик группы, также связан с этим местом</td></tr></tbody></table><h2 id="связанные-группы" tabindex="-1">Связанные группы <a class="header-anchor" href="#связанные-группы" aria-label="Permalink to “Связанные группы”">​</a></h2><ul><li><a href="/Knowledge-Base/bands/agata-kristi.html">Агата Кристи</a></li></ul><h2 id="современныи-статус" tabindex="-1">Современный статус <a class="header-anchor" href="#современныи-статус" aria-label="Permalink to “Современный статус”">​</a></h2><p>Сегодня здание продолжает работать как действующее студенческое общежитие УрФУ. Оно не является музейной площадкой и не отмечено специальными знаками, но включается в неформальные маршруты по местам уральского рока.</p><p>Для поклонников <strong>«Агаты Кристи»</strong> общежитие остаётся местом памяти: сюда приходят как к одной из точек, связанных с ранним, студенческим периодом истории группы.</p><div class="warning custom-block"><p class="custom-block-title">Важно для туристов</p><p>Это действующее студенческое общежитие, поэтому доступ внутрь ограничен. При посещении стоит рассматривать здание как внешнюю точку маршрута и уважать частное пространство жителей.</p></div><h2 id="роль-в-2026-году" tabindex="-1">Роль в 2026 году <a class="header-anchor" href="#роль-в-2026-году" aria-label="Permalink to “Роль в 2026 году”">​</a></h2><p>В рамках Года уральского рока общежитие № 11 планируется включить в экскурсионные маршруты, посвящённые студенческому периоду жизни музыкантов и ранней истории <strong>«Агаты Кристи»</strong>.</p><p>Также в материалах проекта указана планируемая установка памятной таблички на фасаде здания. Она должна зафиксировать связь общежития с уральской рок-культурой и историей группы.</p><h2 id="планируемые-события" tabindex="-1">Планируемые события <a class="header-anchor" href="#планируемые-события" aria-label="Permalink to “Планируемые события”">​</a></h2><table tabindex="0"><thead><tr><th>Период</th><th>Событие</th></tr></thead><tbody><tr><td>2026 год</td><td>Установка памятной таблички на фасаде здания</td></tr><tr><td>2026 год</td><td>Включение общежития в экскурсии по местам «Агаты Кристи»</td></tr><tr><td>2026 год</td><td>Экскурсионные рассказы о студенческом периоде жизни музыкантов</td></tr></tbody></table><h2 id="что-посмотреть-рядом" tabindex="-1">Что посмотреть рядом <a class="header-anchor" href="#что-посмотреть-рядом" aria-label="Permalink to “Что посмотреть рядом”">​</a></h2><p>Общежитие № 11 удобно включать в маршрут по университетским и студенческим местам уральского рока. Его можно связать с другими точками базы знаний:</p><ul><li><a href="/Knowledge-Base/places/urfu-rtf.html">УрФУ, Радиофак / РТФ УПИ</a></li><li><a href="/Knowledge-Base/places/pryanik-urgahu.html">УрГАХУ, корпус «Пряник»</a></li><li><a href="/Knowledge-Base/places/dk-sverdlova.html">ДК имени Свердлова</a></li><li><a href="/Knowledge-Base/places/dvorets-molodezhi.html">Дворец молодёжи</a></li></ul>',32)])])}const b=t(o,[["render",s]]);export{g as __pageData,b as default};
